INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES ("もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 125801, 1, 321, 2, 1, "リリ", 24001, 0, 1, 40011);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES ("初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 126001, 2, 322, 2, 1, "クリア", 24001, 0, 1, 40011);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES ("んーと。\nこれ、あげる。\nはい", 126101, 3, 323, 2, 1, "プレシア", 24001, 0, 1, 40011);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES ("あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 125801, 4, 324, 2, 2, "リリ", 24001, 0, 1, 40011);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES ("こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 126001, 5, 325, 2, 2, "クリア", 24001, 0, 1, 40011);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES ("お兄。\nきてくれて、うれしい", 126101, 6, 326, 2, 2, "プレシア", 24001, 0, 1, 40011);
